// Add this escape function at the top
function escapeMarkdownV2(text) {
  const specialChars = ['_', '*', '[', ']', '(', ')', '~', '`', '>', '#', '+', '-', '=', '|', '{', '}', '.', '!'];
  let escaped = text;
  specialChars.forEach(char => {
    escaped = escaped.split(char).join('\\' + char);
  });
  return escaped;
}

const memories = $('Get Memories').all().map(i => i.json);
const reminders = $('Get Reminders').all().map(i => i.json);

// Filter yesterday's memories using metadata.timestamp
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
yesterday.setHours(0, 0, 0, 0);
const today = new Date(now);
today.setHours(0, 0, 0, 0);

const yesterdayMemories = memories.filter(mem => {
  const ts = mem.metadata?.timestamp;
  if (!ts) return false;
  const memDate = new Date(ts);
  return memDate >= yesterday && memDate < today;
});

let textCount = 0;
let photoCount = 0;

yesterdayMemories.forEach(mem => {
  if (mem.metadata?.type === 'photo') {
    photoCount++;
  } else {
    textCount++;
  }
});

const dateStr = now.toLocaleDateString('en-IN', {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  year: 'numeric'
});

let message = `☀️ *Good Morning\!*\n\n`;
message += `📅 *${escapeMarkdownV2(dateStr)}*\n\n`;

message += `📊 *Yesterday's Activity:*\n`;
if (yesterdayMemories.length === 0) {
  message += `No new memories saved\\.\n\n`;
} else {
  message += `✅ Saved ${yesterdayMemories.length} new ${yesterdayMemories.length === 1 ? 'memory' : 'memories'}\n`;
  if (textCount > 0) message += `   📝 Text: ${textCount}\n`;
  if (photoCount > 0) message += `   📸 Photos: ${photoCount}\n`;
  message += `\n`;
}

message += `⏰ *Today's Reminders:*\n`;
if (reminders.length === 0) {
  message += `No reminders scheduled\\.\n\n`;
} else {
  message += `You have ${reminders.length} ${reminders.length === 1 ? 'reminder' : 'reminders'}:\n\n`;
  reminders.forEach((reminder, index) => {
    const time = new Date(reminder.remind_at).toLocaleTimeString('en-IN', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: true
    });
    message += `${index + 1}\\. ${escapeMarkdownV2(reminder.message)} — ${escapeMarkdownV2(time)}\n`;
  });
  message += `\n`;
}

message += `💡 *Quick Tip:* Send photos/text anytime to save to your Second Brain\\!\n\n`;
message += `_Have a productive day\\! 🚀_`;

return [{ json: { message } }];

const now = new Date();
