yesterday.setHours(0, 0, 0, 0);
const today = new Date(now);
today.setHours(0, 0, 0, 0);

return [{
  json: {
    yesterdayISO: yesterday.toISOString(),
    todayISO: today.toISOString(),
    todayEndISO: new Date(today.setHours(23, 59, 59, 999)).toISOString()
  }
}];
